package com.pazim.smsemailforwarder;
import android.app.Activity; import android.content.*; import android.telephony.SmsManager;
public class SmsStatusReceiver extends BroadcastReceiver { public void onReceive(Context c,Intent i){String id=i.getStringExtra("id");int part=i.getIntExtra("part",0),count=i.getIntExtra("count",1);if(id==null)return;if(getResultCode()==Activity.RESULT_OK){if(part==count-1)HistoryStore.update(c,id,"SENT","All "+count+" SMS part(s) accepted by Android/carrier.");return;}String d;switch(getResultCode()){case SmsManager.RESULT_ERROR_NO_SERVICE:d="No cellular service.";break;case SmsManager.RESULT_ERROR_RADIO_OFF:d="Cellular radio is off.";break;case SmsManager.RESULT_ERROR_NULL_PDU:d="Invalid SMS data.";break;default:d="SMS failed. Error code: "+getResultCode();}HistoryStore.update(c,id,"FAILED",d);}}
